#include <stdio.h>
#include <stdlib.h>

int main() {
  int *numbers = (int *)malloc(3 * sizeof(int));
  if (numbers == NULL) {
    printf("Memory allocation failed!\n");
    return 1;
  }
  numbers[0] = 10;
  numbers[1] = 20;
  numbers[2] = 30;
  printf("Numbers: %d, %d, %d\n", numbers[0], numbers[1], numbers[2]);
  free(numbers);
  return 0;
}
// Output:
// Numbers: 10, 20, 30

#include <stdio.h>
#include <stdlib.h>

int main() {
  int *numbers = (int *)calloc(3, sizeof(int));
  if (numbers == NULL) {
    printf("Memory allocation failed!\n");
    return 1;
  }
  printf("Initialized values: %d, %d, %d\n", numbers[0], numbers[1], numbers[2]);
  numbers[0] = 100;
  printf("Modified value: %d\n", numbers[0]);
  free(numbers);
  return 0;
}
// Output:
// Initialized values: 0, 0, 0
// Modified value: 100

#include <stdio.h>
#include <stdlib.h>

int main() {
  int *numbers = (int *)malloc(2 * sizeof(int));
  if (numbers == NULL) {
    printf("Memory allocation failed!\n");
    return 1;
  }
  numbers[0] = 5;
  numbers[1] = 10;
  printf("Original: %d, %d\n", numbers[0], numbers[1]);
  numbers = (int *)realloc(numbers, 4 * sizeof(int));
  if (numbers == NULL) {
    printf("Memory reallocation failed!\n");
    return 1;
  }
  numbers[2] = 15;
  numbers[3] = 20;
  printf("After realloc: %d, %d, %d, %d\n", numbers[0], numbers[1], numbers[2], numbers[3]);
  free(numbers);
  return 0;
}
// Output:
// Original: 5, 10
// After realloc: 5, 10, 15, 20

